	.yith-wcan-filter[data-taxonomy*="grudu"] ul.filter-label li a:hover {
		background: var(--ps-green-light);
	}
	.yith-wcan-filter[data-taxonomy*="grudu"] ul.filter-label li.chosen a,
	.yith-wcan-filter[data-taxonomy*="grudu"] ul.filter-label li a.active {
		background: var(--ps-green);
	}
	.yith-wcan-filter[data-taxonomy*="grudu"] ul.filter-label li.chosen a .term-label,
	.yith-wcan-filter[data-taxonomy*="grudu"] ul.filter-label li a.active .term-label {
