	.yith-wcan-filter[data-taxonomy*="amzius"] ul.filter-label li a:hover {
		border-color: var(--ps-green); background: #fff;
	}
	.yith-wcan-filter[data-taxonomy*="amzius"] ul.filter-label li a:hover .term-label {
		color: var(--ps-green);
	}
	.yith-wcan-filter[data-taxonomy*="amzius"] ul.filter-label li.chosen a,
	.yith-wcan-filter[data-taxonomy*="amzius"] ul.filter-label li a.active {
		background: var(--ps-green); border-color: var(--ps-green);
	}
	.yith-wcan-filter[data-taxonomy*="amzius"] ul.filter-label li.chosen a .term-label,
	.yith-wcan-filter[data-taxonomy*="amzius"] ul.filter-label li a.active .term-label {
		color: #fff;
	}

	/* ===== CHECKBOX SARASAI ===== */
	.yith-wcan-filters ul.filter-checkbox,
	.yith-wcan-filters .checkbox-design ul { list-style: none; margin: 0; padding: 0; }
	.yith-wcan-filters ul.filter-checkbox li,
	.yith-wcan-filters .checkbox-design ul li {
		margin: 0 0 4px; padding: 0; list-style: none;
		border: none !important; background: none !important;
	}
	.yith-wcan-filters ul.filter-checkbox li a,
	.yith-wcan-filters ul.filter-checkbox li label,
	.yith-wcan-filters .checkbox-design ul li label {
		display: flex; align-items: center; gap: 7px;
		font-size: 13px; line-height: 1.35; color: var(--ps-text);
		cursor: pointer; transition: color .12s ease;
		text-decoration: none;
	}
	.yith-wcan-filters ul.filter-checkbox li a:hover,
	.yith-wcan-filters .checkbox-design ul li label:hover { color: var(--ps-green); }
	.yith-wcan-filters ul.filter-checkbox li.chosen a,
	.yith-wcan-filters .checkbox-design ul li.chosen label {
		color: var(--ps-green); font-weight: 600;
	}
	.yith-wcan-filters input[type="checkbox"] {
		accent-color: var(--ps-green);
		width: 15px; height: 15px; margin: 0; flex-shrink: 0; cursor: pointer;
	}

	/* ===== SHOW MORE ===== */
	.yith-wcan-filters .show-more,
	.yith-wcan-filters a.shorten-link {
		display: inline-block; margin-top: 6px;
		color: var(--ps-green); font-size: 12px; font-weight: 600;
		cursor: pointer; text-decoration: none;
	}
	.yith-wcan-filters .show-more:hover { text-decoration: underline; }

	/* ===== BRANDAS (Select) ===== */
	.yith-wcan-filters select {
		width: 100%; padding: 7px 11px;
		border: 1.5px solid var(--ps-border); border-radius: 8px;
		font-size: 13px; color: var(--ps-text); background: #fff;
	}
	.yith-wcan-filters .yith-wcan-dropdown ul li { margin: 0 0 3px; }
	.yith-wcan-filters .yith-wcan-dropdown ul li label {
