	}

	/* ===== AKTYVUS FILTRAI ===== */
	.yith-wcan-active-filters { margin-bottom: 12px; }

	/* ===== v13: FILTRO TARPU SUTRAUKIMAS (checkbox sarasai; pill NEPALIESTI) ===== */
	.yith-wcan-filters .yith-wcan-filter {
		margin-bottom: 12px !important;
		padding-bottom: 10px !important;
	}
	.yith-wcan-filters .filter-content { margin-top: 4px !important; }
	.yith-wcan-filters .filter-content ul:not(.filter-label) li {
